1	# template
2	
3	# 1. 정의
4	
5	## 메타 언어(meta language)
6	
7	언어를 기술하는 언어
8	
9	## 메타 언어를 왜 설명하는 가
10	
11	C++의 **template**은 메타 클래스로, 이것을 설명하기 위해서는 어디서 유래되었는지 알 필요가 있다.
12	
13	→ 메타 클래스 : 클래스를 기술하기 위한 클래스
14	
15	명시적 인스턴스화는 **템플릿의 선언과 정의를 같은 파일에 작성한다.**
16	
17	## 종류
18	
19	- 일반화된 클래스(generic class)
20	- 파라미터를 받는 클래스(parameterized class)
21	- 템플릿 클래스(template class)
22	
23	## 명시적 지정(explicit specification)
24	
25	**인스턴스화를 개발자가 코드 생성 시점을 결정하는 방식이다.**
26	
27	→ 효율적인 코드 컴파일과 링크 시간을 얻을 수 있다.
28	
29	```cpp
30	// Stack.h
31	
32	#ifndef STACK_H
33	#define STACK_H
34	
35	template <typename T>
36	class Stack {
37	 private:
38	  std::vector<T> mStack;
39	
40	 public:
41	  void Push(T val);
42	  T Pop();
43	  bool IsEmpty() const;
44	};
45	
46	// 어떠한 타입들이 명시적으로 인스턴스화되는지 알려주기 위한 타입데프들
47	typedef Stack<short> ShortStack;
48	typedef Stack<int> IntStack;
49	typedef Stack<float> FloatStack;
50	typedef Stack<double> DoubleStack;
51	
52	#endif
53	```
54	
55	```cpp
56	// Stack.cpp
57	 
58	#include "stack.h"
59	 
60	template <typename T>
61	void Stack<T>::Push(T val)
62	{
63	    mStack.push_back(val);
64	}
65	 
66	template <typename T>
67	T Stack<T>::Pop()
68	{
69	    if (IsEmpty())
70	        return T();
71	 
72	    T val = mStack.back();
73	    mStack.pop_back();
74	    return val;
75	}
76	 
77	template <typename T>
78	bool Stack<T>::IsEmpty() const
79	{
80	    return mStack.empty();
81	}
82	 
83	// 명시적 템플릿 인스턴스화 선언
84	template class Stack<short>;
85	template class Stack <int>;
86	template class Stack<float>;
87	template class Stack<double>;
88	```
89	
90	```cpp
91	// main.cc
92	int main() {
93	  Stack<int> a;
94	  Stack<char> b;
95	
96	  a.Push(2);
97	  b.Push('2');
98	
99	  return 0;
100	}
101	```
102	
103	![Untitled](template/Untitled.png)
104	
105	이 템플릿 클래스는 short, int, float, double 타입에 대해 명시적으로 인스턴스화 된다. char는 인스터화 되는 이유는 이 템플릿이 모호하지 않은 템플릿으로 컴파일에서 자동으로 인스터화 해준다.
106	
107	하지만
108	
109	# 2. template class
110	
111	간단하게 말하면, 템플릿 개념이 클래스에 적용되는 의미이다. 
112	
113	```cpp
114	template <class T>
115	class cStack {
116	 public:
117	  cStack(int n) {
118	    data = new T[size = s];
119	    sp = 0;
120	  }
121	  ~cStack() { delete[] data; }
122	  void Push(T d);
123	  T Pop();
124	
125	 private:
126	  T *data;
127	  int size, sp;
128	};
129	
130	template <class T>
131	void cStack<T>::Push(T d) {
132	  data[sp] = d;
133	  ++sp;
134	}
135	
136	template <class T>
137	T cStack<T>::Pop() {
138	  --sp;
139	  return data[sp];
140	}
141	```
142	
143	```cpp
144	int main() {
145	  cStack<char> s(10);
146	  cStack<int> t(10);
147	  
148	  s.Push('A');
149	  s.Push('a');
150	  t.Push(100);
151	  t.Push(1);
152	  
153	  printf("%c\n", s.Pop());
154	  printf("%c\n", t.Pop());
155	
156	  return 0;
157	}
158	```
159	
160	위 코드처럼 클래스를 템플릿으로 만, 여러 응용 할 수 있습니다. 
161	
162	# 3. template function
163	
164	여러 다른 자료형에 대하여 같은 역할을 하는 하나의 함수 계열을 하나의 템플릿으로 표현할 수 있다.
165	
166	```cpp
167	template <typename Type>
168	Type max(Type a, Type b) {
169	    return a > b ? a : b;
170	}
171	```
172	
173	```cpp
174	int main()
175	{
176	  // This will call max <int> (by argument deduction)
177	  std::cout << max(3, 7) << std::endl;
178	  // This will call max<double> (by argument deduction)
179	  std::cout << max(3.0, 7.0) << std::endl;
180	  return 0;
181	}
182	```
183	
184	```cpp
185	// 출력결과
186	7
187	7
188	```
189	
190	컴파일러는 들어오는 자료 형태를 각각 int와 double로 추론한다.
191	
192	하지만
193	
194	```cpp
195	std::cout << max<double>(3, 7.0) << std::endl;
196	```
197	
198	이런 형태는 실패한다. 왜냐하면 인자로 넘어오는 두가지 자료형이 정확하게 같다고 정의되어 있기 때문이다. 
