114	
115	위 코드 처럼 정의는 불가능하다.!!! 위 operator은 일반 함수이다. 특정 클래스의 멤버 함수가 아니다
116	
117	x+y → x.operator(y)로 변역된므로, 함축적 호출 2개의 파라미터로 명시하는 것은 불가능 하다. 만약 위 연산자 함수가 정의 된다면, **x.operator(y,z)를 호출**하기 위해서는 “ **x+y,z** “ 이렇게 명시해야 한다. 하지만 이것은 **문법적 에러**이다.
118	
119	→ friend 키워드를 사용하면 문제가 풀린다.
120	
121	**일반 함수의 연산자 오버로딩은 반드시 친구 함수로 구현하라**
122	
123	```cpp
124	#include <stdio.h>
125	
126	class CComplex
127	{
128	public:
129		CComplex(float ta = 0, float tb = 0) {
130			a = ta, b = tb;
131		}
132		void Print();
133		friend CComplex operator+(CComplex x, CComplex y);
134		friend CComplex operator+(float f, CComplex y);
135	private:
136		float a, b;
137	};
138	
139	void CComplex::Print() {
140		printf("%2.2f%+%2.2fi\n", a, b);
141	}
142	
143	CComplex operator+(CComplex x, CComplex y) {
144	// 이제 operator+에서 CComplex의 private 멤버를 접근하는 것이 허용된다.
145	// CComplex는 이 함수를 친구로 생각하고 있는 것이다.
146		CComplex t(x.a, x.b);
147	
148		t.a += y.a;
149		t.b += y.b;
150	
151		return t;
152	}
153	
154	CComplex operator+(float f, CComplex y) {
155		CComplex t(f);
156	
157		t.a += y.a;
158		t.b += y.b;
159	
160		return t;
161	}
162	
163	int main() {
164		CComplex x(1., 2.), y(3., 4.), z;
165		z = 3 + y;
166		z = x + y;
167		z.Print();
168	}
169	```
