29	void CreateVertexBuffer(const vector<T_VERTEX> &vertices,
30	                        ComPtr<ID3D11Buffer> &vertexBuffer) {
31	
32	    // D3D11_USAGE enumeration (d3d11.h)
33	    // https://learn.microsoft.com/en-us/windows/win32/api/d3d11/ne-d3d11-d3d11_usage
34	
35	    D3D11_BUFFER_DESC bufferDesc;
36	    ZeroMemory(&bufferDesc, sizeof(bufferDesc));
37	    bufferDesc.Usage = D3D11_USAGE_IMMUTABLE; // 초기화 후 변경X
38	    bufferDesc.ByteWidth = UINT(sizeof(T_VERTEX) * vertices.size());
39	    bufferDesc.BindFlags = D3D11_BIND_VERTEX_BUFFER;
40	    bufferDesc.CPUAccessFlags = 0; // 0 if no CPU access is necessary.
41	    bufferDesc.StructureByteStride = sizeof(T_VERTEX);
42	
43	    D3D11_SUBRESOURCE_DATA vertexBufferData = {0}; // MS 예제에서 초기화하는 방식
44	    vertexBufferData.pSysMem = vertices.data();
45	    vertexBufferData.SysMemPitch = 0;
46	    vertexBufferData.SysMemSlicePitch = 0;
47	
48	    const HRESULT hr = m_device->CreateBuffer(
49	        &bufferDesc, &vertexBufferData, vertexBuffer.GetAddressOf());
50	    if (FAILED(hr)) {
51	        std::cout << "CreateBuffer() failed. " << std::hex << hr
52	                  << std::endl;
53	    };
54	}
